// State-level mental health data with mixed official and modeled metrics
export interface StateData {
  state: string;
  abbreviation: string;
  population: number; // State population for per capita calculations
  official_source_period?: string;
  // Core metrics (percentages)
  ami: number;
  ami_total?: number;
  smi: number;
  smi_total?: number;
  mde_adult: number;
  mde_adult_total?: number;
  mde_youth: number;
  mde_youth_total?: number;
  suicide_rate: number;
  suicide_deaths?: number;
  suicide_source_year?: number;
  treatment_access: number;
  // Core metrics (per capita per 100k)
  ami_per_capita: number;
  smi_per_capita: number;
  mde_adult_per_capita: number;
  mde_youth_per_capita: number;
  // Additional psychiatric disorders (percentages)
  anxiety_disorder: number;
  ptsd: number;
  substance_use_disorder: number;
  substance_use_disorder_total?: number;
  opioid_use_disorder: number;
  opioid_use_disorder_total?: number;
  alcohol_use_disorder: number;
  alcohol_use_disorder_total?: number;
  bipolar_disorder: number;
  schizophrenia: number;
  eating_disorder: number;
  adhd: number;
  // Additional psychiatric disorders (per capita per 100k)
  anxiety_disorder_per_capita: number;
  ptsd_per_capita: number;
  substance_use_disorder_per_capita: number;
  opioid_use_disorder_per_capita: number;
  alcohol_use_disorder_per_capita: number;
  bipolar_disorder_per_capita: number;
  schizophrenia_per_capita: number;
  eating_disorder_per_capita: number;
  adhd_per_capita: number;
  // Geographic coordinates
  lat: number;
  lng: number;
}

export interface ForecastData {
  year: number;
  ami: number;
  smi: number;
  mde_adult: number;
  mde_youth: number;
  suicide_rate: number;
  anxiety_disorder: number;
  ptsd: number;
  substance_use_disorder: number;
  opioid_use_disorder: number;
  alcohol_use_disorder: number;
  bipolar_disorder: number;
  schizophrenia: number;
  eating_disorder: number;
  adhd: number;
}

export interface StateResources {
  state: string;
  abbreviation: string;
  resource_source_period?: string;
  hotline: string;
  crisis_text: string;
  mental_health_providers: number;
  psychiatrists: number;
  therapists: number;
  crisis_centers: number;
  mental_health_facilities?: number;
  support_organizations: string[];
}

type RawStateData = Omit<StateData, "mde_adult" | "mde_adult_total" | "mde_adult_per_capita">;

// Helper function to calculate per capita values
const calcPerCapita = (percentage: number): number => {
  return Math.round((percentage / 100) * 100000 * 10) / 10;
};

const calcPer100kFromTotal = (total: number, population: number): number => {
  return Math.round((total / population) * 100000 * 10) / 10;
};

