export const stateData: StateData[] = rawStateData.map((state) => {
  const official = officialNsduhStateMetrics[state.abbreviation];
  const officialSuicide = officialCdcStateSuicideRates[state.abbreviation];
  const fallbackAdultMde = Math.round(state.mde_youth * 0.7 * 100) / 100;
  const fallbackAdultMdeTotal = Math.round((fallbackAdultMde / 100) * state.population);

  return {
    ...state,
    mde_adult: official?.mde_adult ?? fallbackAdultMde,
    mde_adult_total: official?.mde_adult_total ?? fallbackAdultMdeTotal,
    mde_adult_per_capita: calcPer100kFromTotal(official?.mde_adult_total ?? fallbackAdultMdeTotal, state.population),
    ...(official
      ? {
          official_source_period: official.sourcePeriod,
          ami: official.ami,
          ami_total: official.ami_total,
          ami_per_capita: calcPer100kFromTotal(official.ami_total, state.population),
          smi: official.smi,
          smi_total: official.smi_total,
          smi_per_capita: calcPer100kFromTotal(official.smi_total, state.population),
          mde_adult: official.mde_adult,
          mde_adult_total: official.mde_adult_total,
          mde_adult_per_capita: calcPer100kFromTotal(official.mde_adult_total, state.population),
          mde_youth: official.mde_youth,
          mde_youth_total: official.mde_youth_total,
          mde_youth_per_capita: calcPer100kFromTotal(official.mde_youth_total, state.population),
          substance_use_disorder: official.substance_use_disorder,
          substance_use_disorder_total: official.substance_use_disorder_total,
          substance_use_disorder_per_capita: calcPer100kFromTotal(official.substance_use_disorder_total, state.population),
          opioid_use_disorder: official.opioid_use_disorder,
          opioid_use_disorder_total: official.opioid_use_disorder_total,
          opioid_use_disorder_per_capita: calcPer100kFromTotal(official.opioid_use_disorder_total, state.population),
          alcohol_use_disorder: official.alcohol_use_disorder,
          alcohol_use_disorder_total: official.alcohol_use_disorder_total,
          alcohol_use_disorder_per_capita: calcPer100kFromTotal(official.alcohol_use_disorder_total, state.population),
        }
      : {}),
    ...(officialSuicide
      ? {
          suicide_rate: officialSuicide.suicide_rate,
          suicide_deaths: officialSuicide.suicide_deaths,
          suicide_source_year: officialSuicide.sourceYear,
        }
      : {}),
  };
});

// 10-year forecasting data (2024-2034)
export const generateForecast = (state: StateData): ForecastData[] => {
  const forecasts: ForecastData[] = [];
  for (let i = 0; i <= 10; i++) {
    const year = 2024 + i;
    // Forecast with slight increase trend based on historical patterns
    const ami_trend = state.ami + (i * 0.15);
    const smi_trend = state.smi + (i * 0.08);
    const mde_adult_trend = state.mde_adult + (i * 0.1);
    const mde_trend = state.mde_youth + (i * 0.12);
    const suicide_trend = state.suicide_rate + (i * 0.05);
    const anxiety_trend = state.anxiety_disorder + (i * 0.12);
    const ptsd_trend = state.ptsd + (i * 0.06);
    const sud_trend = state.substance_use_disorder + (i * 0.10);
    const opioid_trend = state.opioid_use_disorder + (i * 0.08);
    const alcohol_trend = state.alcohol_use_disorder + (i * 0.07);
    const bipolar_trend = state.bipolar_disorder + (i * 0.04);
    const schizo_trend = state.schizophrenia + (i * 0.02);
    const eating_trend = state.eating_disorder + (i * 0.03);
    const adhd_trend = state.adhd + (i * 0.05);
    
    forecasts.push({
      year,
      ami: Math.round(ami_trend * 10) / 10,
      smi: Math.round(smi_trend * 10) / 10,
      mde_adult: Math.round(mde_adult_trend * 10) / 10,
      mde_youth: Math.round(mde_trend * 10) / 10,
      suicide_rate: Math.round(suicide_trend * 10) / 10,
      anxiety_disorder: Math.round(anxiety_trend * 10) / 10,
      ptsd: Math.round(ptsd_trend * 10) / 10,
      substance_use_disorder: Math.round(sud_trend * 10) / 10,
      opioid_use_disorder: Math.round(opioid_trend * 10) / 10,
      alcohol_use_disorder: Math.round(alcohol_trend * 10) / 10,
      bipolar_disorder: Math.round(bipolar_trend * 10) / 10,
      schizophrenia: Math.round(schizo_trend * 10) / 10,
      eating_disorder: Math.round(eating_trend * 10) / 10,
      adhd: Math.round(adhd_trend * 10) / 10,
    });
  }
  return forecasts;
};

export const getMetricColor = (metric: string, value: number): string => {
  const values = stateData
    .map((state) => state[metric as keyof StateData])
    .filter((entry): entry is number => typeof entry === "number");

  if (!values.length) return "#10b981";

  const range = {
    min: Math.min(...values),
    max: Math.max(...values),
  };
  const normalized = range.max === range.min ? 0.5 : (value - range.min) / (range.max - range.min);
  const hue = (1 - normalized) * 120; // Green (120) to Red (0)
  return `hsl(${hue}, 70%, 50%)`;
};

